import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const i="/assets/reference%20ardusub%20sensors.DenS34IW.",s="/assets/reference%20ardusub%20sensors%20accelerometer.BjtNG7aG.",l="/assets/reference%20ardusub%20sensors%20compass.fgbSJRh-.",g=JSON.parse('{"title":"Sensors Setup Page","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/sensors-setup-page.md","filePath":"robotics/sensors-setup-page.md"}'),n={name:"robotics/sensors-setup-page.md"};function c(h,e,u,p,b,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="sensors-setup-page" tabindex="-1">Sensors Setup Page <a class="header-anchor" href="#sensors-setup-page" aria-label="Permalink to &quot;Sensors Setup Page&quot;">​</a></h1><p>The Sensors Setup page allows users to calibrate the vehicle&#39;s accelerometer, compass, pressure sensor.</p><p>Available sensors are displayed as a list of buttons beside the sidebar. Sensors marked with green are already calibrated, while sensors marked with red require calibration prior to operation. Sensors with no color marks are simple calibrations that are optional.</p><p><img src="'+i+'" alt=""></p><h2 id="accelerometer-calibration" tabindex="-1">Accelerometer Calibration <a href="#accelerometer-calibration" id="accelerometer-calibration"></a> <a class="header-anchor" href="#accelerometer-calibration" aria-label="Permalink to &quot;Accelerometer Calibration &lt;a href=&quot;#accelerometer-calibration&quot; id=&quot;accelerometer-calibration&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><p>To calibrate the autopilot&#39;s accelerometers the vehicle will need to be placed and held in a number of orientations.</p><p>The calibration steps are:</p><ol><li>Click the <strong>Accelerometer</strong> sensor button.</li><li>Click OK to start the calibration.</li><li>Position the vehicle based on text instructions in the center display.</li><li>Click the Next button to capture each position.</li></ol><h3 id="compass-calibration" tabindex="-1">Compass Calibration <a href="#compass-calibration" id="compass-calibration"></a> <a class="header-anchor" href="#compass-calibration" aria-label="Permalink to &quot;Compass Calibration &lt;a href=&quot;#compass-calibration&quot; id=&quot;compass-calibration&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><img src="'+l+'" alt=""></p><p>The calibration steps are:</p><ol><li>Click the <strong>Compass</strong> sensor button.</li><li>Click OK to start the calibration.</li><li>You need to rotate the vehicle randomly around all axes until the progress bar fills all the way to the right and the calibration completes.</li><li>When the calibration completes you will get the following results:</li></ol><h3 id="level-horizon" tabindex="-1">Level Horizon <a href="#level-horizon" id="level-horizon"></a> <a class="header-anchor" href="#level-horizon" aria-label="Permalink to &quot;Level Horizon &lt;a href=&quot;#level-horizon&quot; id=&quot;level-horizon&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If the horizon (as shown in the HUD) is not level after completing accelerometer calibration you can calibrate the level horizon for your vehicle. You will be asked to place the vehicle in a level orientation while it captures the information.</p><p>Place the vehicle in its level flight orientation on a level surface: For planes this is the position during level flight (planes tend to have their wings slightly pitched up!) For copters this is the hover position. Click OK to start the calibration.</p><h3 id="calibrate-pressure" tabindex="-1">Calibrate Pressure <a href="#calibrate-pressure" id="calibrate-pressure"></a> <a class="header-anchor" href="#calibrate-pressure" aria-label="Permalink to &quot;Calibrate Pressure &lt;a href=&quot;#calibrate-pressure&quot; id=&quot;calibrate-pressure&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>This calibration set&#39;s the altitude to zero at the current pressure. To perform Pressure calibration: Click the Calibrate Pressure button and then Ok.</p><p>The calibration result is immediately displayed.</p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',22)])])}const f=t(n,[["render",c]]);export{g as __pageData,f as default};
